class Solution {
public:
    int alternateDigitSum(int n) {
        int sign = 1;
        int sum = 0;
        while (n) {
            int digit = n % 10;
            sum += sign * digit;
            sign *= -1;
            n /= 10;
        }
        return sum;
    }
};
```

